namespace CreditCardApi.Domain.Entities;

/// <summary>
/// A credit card owned by a cardholder. The aggregate root of the card/transaction relationship.
/// </summary>
/// <remarks>
/// The full card number (PAN) is deliberately absent from this model: only the last four digits
/// are retained (see <see cref="Cards.CardNumber"/>), so a database or log leak can never expose
/// a usable card number. CVV/PIN/track data are never accepted nor stored anywhere.
/// </remarks>
public class CreditCard
{
    /// <summary>Surrogate primary key, generated by the database.</summary>
    public int Id { get; set; }

    /// <summary>Name of the cardholder as embossed on the card. Required, non-empty.</summary>
    public string CardholderName { get; set; } = string.Empty;

    /// <summary>The only digits of the PAN that are ever persisted.</summary>
    public string CardNumberLast4 { get; set; } = string.Empty;

    /// <summary>Card scheme, e.g. <c>VISA</c> or <c>MASTERCARD</c>. Optional.</summary>
    public string? Brand { get; set; }

    /// <summary>Credit limit of the card. Never negative.</summary>
    public decimal CreditLimit { get; set; }

    /// <summary>UTC timestamp assigned by the server when the card was created.</summary>
    public DateTime CreatedAt { get; set; }

    /// <summary>Transactions charged against this card (1:N).</summary>
    public ICollection<Transaction> Transactions { get; } = [];
}
